const { Pool } = require('pg');
const crypto = require('crypto');

// Generate a secure random password for application user
const generateSecurePassword = () => {
  return crypto.randomBytes(32).toString('hex');
};

// Database connection pool configuration
const pool = new Pool({
  user: 'postgres',
  host: 'localhost',
  database: 'your_database',
  password: process.env.DB_PASSWORD || 'your_superuser_password',
  port: 5432,
  max: 20,
  idleTimeoutMillis: 30000,
  connectionTimeoutMillis: 2000,
});

// Create application user with limited permissions
const createAppUser = async () => {
  const client = await pool.connect();
  try {
    await client.query('BEGIN');
    
    // Create application user with random password
    const appUserPassword = generateSecurePassword();
    await client.query(
      `CREATE USER app_user WITH PASSWORD '${appUserPassword}' NOCREATEDB NOCREATEROLE NOSUPERUSER`
    );
    
    // Grant minimal required permissions
    await client.query('GRANT CONNECT ON DATABASE your_database TO app_user');
    await client.query('GRANT USAGE ON SCHEMA public TO app_user');
    await client.query('GRANT SELECT, INSERT, UPDATE, DELETE ON ALL TABLES IN SCHEMA public TO app_user');
    await client.query('GRANT USAGE, SELECT ON ALL SEQUENCES IN SCHEMA public TO app_user');
    
    await client.query('COMMIT');
    
    // Store password securely (in production, use environment variables or secure vault)
    console.log('Application user created with password:', appUserPassword);
    
    return appUserPassword;
  } catch (error) {
    await client.query('ROLLBACK');
    throw error;
  } finally {
    client.release();
  }
};

// CRUD Operations for Users Table
const createUser = async (userData) => {
  const client = await pool.connect();
  try {
    const result = await client.query(
      'INSERT INTO users (name, email, created_at) VALUES ($1, $2, NOW()) RETURNING *',
      [userData.name, userData.email]
    );
    return result.rows[0];
  } finally {
    client.release();
  }
};

const getUsers = async () => {
  const client = await pool.connect();
  try {
    const result = await client.query('SELECT * FROM users ORDER BY created_at DESC');
    return result.rows;
  } finally {
    client.release();
  }
};

